import { ChatRoom } from "./chat-room.js";
export { ChatRoom };

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const room = url.searchParams.get("room") || "lobby";

    // Only accept WebSocket upgrade requests
    if (request.headers.get("Upgrade") !== "websocket") {
      return new Response("Expected a WebSocket upgrade", { status: 426 });
    }

    // Resolve the ONE Durable Object for this room name
    const id = env.ROOMS.idFromName(room);
    const stub = env.ROOMS.get(id);

    // Forward the upgrade request to that room object
    return stub.fetch(request);
  },
};

import { DurableObject } from "cloudflare:workers";

export class ChatRoom extends DurableObject {
  constructor(ctx, env) {
    super(ctx, env);
    this.ctx = ctx;
    this.env = env;
  }

  // Completes the WebSocket handshake and registers the socket
  async fetch(request) {
    const url = new URL(request.url);
    const room = url.searchParams.get("room") || "lobby";

    const pair = new WebSocketPair();
    const client = pair[0];
    const server = pair[1];

    // Hibernation: let the runtime hold the socket so the DO can sleep
    this.ctx.acceptWebSocket(server);
    server.serializeAttachment({ room });

    return new Response(null, { status: 101, webSocket: client });
  }

  // Runs whenever ANY connected client sends a message
  async webSocketMessage(ws, raw) {
    const { user, body } = JSON.parse(raw);
    const { room } = ws.deserializeAttachment();
    const created_at = Date.now();

    // 1) Persist to D1 history
    await this.env.DB
      .prepare("INSERT INTO messages (room_id, user, body, created_at) VALUES (?, ?, ?, ?)")
      .bind(room, user, body, created_at)
      .run();

    // 2) Broadcast to everyone connected to THIS room
    const payload = JSON.stringify({ user, body, created_at });
    for (const socket of this.ctx.getWebSockets()) {
      socket.send(payload);
    }
  }

  async webSocketClose(ws, code, reason, wasClean) {
    ws.close(code, "room closing socket");
  }
}
